package com.example.visprog

import android.Manifest
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.Service
import android.app.usage.NetworkStats
import android.app.usage.NetworkStatsManager
import android.content.Intent
import android.content.pm.PackageManager
import android.content.pm.ServiceInfo
import android.hardware.Sensor
import android.hardware.SensorEvent
import android.hardware.SensorEventListener
import android.hardware.SensorManager
import android.net.ConnectivityManager
import android.net.NetworkCapabilities
import android.os.Environment
import android.os.IBinder
import android.os.Looper
import android.os.PowerManager
import android.telephony.CellIdentityNr
import android.telephony.CellInfo
import android.telephony.CellInfoGsm
import android.telephony.CellInfoLte
import android.telephony.CellInfoNr
import android.telephony.CellSignalStrengthNr
import android.telephony.SignalStrength
import android.telephony.TelephonyCallback
import android.telephony.TelephonyManager
import android.util.Log
import androidx.core.app.ActivityCompat
import androidx.core.app.NotificationCompat
import com.example.visprog.config.ServerConfig
import com.example.visprog.data.LocationData
import com.example.visprog.utils.TelephonyDataBus
import com.google.android.gms.location.FusedLocationProviderClient
import com.google.android.gms.location.LocationCallback
import com.google.android.gms.location.LocationRequest
import com.google.android.gms.location.LocationResult
import com.google.android.gms.location.LocationServices
import com.google.android.gms.location.Priority
import com.google.gson.Gson
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.delay
import kotlinx.coroutines.isActive
import kotlinx.coroutines.launch
import kotlinx.coroutines.runBlocking
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock
import org.zeromq.SocketType
import org.zeromq.ZMQ
import java.io.File
import java.util.ArrayDeque
import kotlin.math.log10
import kotlin.math.max
import kotlin.math.pow
import kotlin.math.roundToInt

class TelephonyService : Service(), SensorEventListener {
    private val tag = "TelephonyService"
    private val channelId = "telephony_service_channel"
    private val gson = Gson()

    private lateinit var sensorManager: SensorManager
    private var pressureValue: Float = 0f
    private var azimuthValue: Float = 0f

    private lateinit var fusedLocationClient: FusedLocationProviderClient
    private lateinit var locationCallback: LocationCallback
    private var currentLocation: LocationData? = null
    private val currentLocExtras = mutableMapOf<String, Any>()

    private var zmqContext: ZMQ.Context? = null
    private var pushSocket: ZMQ.Socket? = null
    private var pullSocket: ZMQ.Socket? = null
    private val socketMutex = Mutex()
    private var lastSuccessfulSend: Long = System.currentTimeMillis()

    private val serviceJob = SupervisorJob()
    private val serviceScope = CoroutineScope(Dispatchers.IO + serviceJob)
    private var wakeLock: PowerManager.WakeLock? = null
    private lateinit var logFile: File

    private var filterLocation = true
    private var filterTelephony = true
    private var filterNetwork = true
    private var smoothGps = true
    private var dataCollectionDelay = 500L

    private var latestCellInfo: List<CellInfo> = emptyList()
    private var totalPacketsSent = 0
    private var lastNotificationUpdateTime = 0L

    private var lastNetworkData: NetworkUsageData? = null
    private var lastNetworkQueryTime: Long = 0L

    private val pathLossHistory = mutableMapOf<String, ArrayDeque<Double>>()
    private val kalmanFilters = mutableMapOf<String, KalmanFilter>()
    private val latFilter = KalmanFilter(q = 0.000001, r = 0.00001) // High precision for GPS
    private val lonFilter = KalmanFilter(q = 0.000001, r = 0.00001)
    private var lastPrimaryCellKey: String? = null

    private val sendBuffer = ArrayDeque<String>()
    private val MAX_BUFFER_SIZE = 100

    class KalmanFilter(private val q: Double = 0.1, private val r: Double = 1.0) {
        private var x = 0.0 // State
        private var p = 1.0 // Covariance
        private var initialized = false

        fun filter(measurement: Double): Double {
            if (!initialized) {
                x = measurement
                initialized = true
                return x
            }
            // Prediction
            p += q
            // Update
            val k = p / (p + r)
            x += k * (measurement - x)
            p *= (1 - k)
            return x
        }
    }

    data class NetworkUsageData(val totalBytesSent: Long, val totalBytesReceived: Long, val topApps: List<AppUsage>? = null)
    data class AppUsage(val packageName: String, val bytes: Long)

    private fun isNetworkCellular(): Boolean {
        val cm = getSystemService(CONNECTIVITY_SERVICE) as ConnectivityManager
        val nc = cm.activeNetwork ?: return false
        val caps = cm.getNetworkCapabilities(nc) ?: return false
        return caps.hasTransport(NetworkCapabilities.TRANSPORT_CELLULAR)
    }

    override fun onCreate() {
        super.onCreate()
        createNotificationChannel()
        updateNotification("Service started", 0, 0)

        fusedLocationClient = LocationServices.getFusedLocationProviderClient(this)
        sensorManager = getSystemService(SENSOR_SERVICE) as SensorManager
        sensorManager.getDefaultSensor(Sensor.TYPE_PRESSURE)?.let {
            sensorManager.registerListener(this, it, SensorManager.SENSOR_DELAY_NORMAL)
        }
        sensorManager.getDefaultSensor(Sensor.TYPE_ROTATION_VECTOR)?.let {
            sensorManager.registerListener(this, it, SensorManager.SENSOR_DELAY_NORMAL)
        }

        val documentsDir = getExternalFilesDir(Environment.DIRECTORY_DOCUMENTS) ?: filesDir
        if (!documentsDir.exists()) documentsDir.mkdirs()
        logFile = File(documentsDir, "telephony_log.json")

        setupLocationUpdates()
        listenTelephony()

        serviceScope.launch {
            initSockets()
            startDataCollection()
            startConnectionMonitor()
            startCommandListener()
        }
        acquireWakeLock()
    }

    private var errorCount = 0

    private fun updateNotification(text: String, count: Int, cellsCount: Int) {
        val now = System.currentTimeMillis()
        if (now - lastNotificationUpdateTime < 1000 && count != 0) return
        lastNotificationUpdateTime = now

        val notification = NotificationCompat.Builder(this, channelId)
            .setContentTitle("Telephony Tracking: $text")
            .setContentText("Sent: $totalPacketsSent | Errors: $errorCount | Cells: $cellsCount")
            .setSmallIcon(R.drawable.ic_launcher_foreground)
            .setPriority(NotificationCompat.PRIORITY_HIGH)
            .setOngoing(true)
            .setOnlyAlertOnce(true)
            .build()

        startForeground(1, notification, ServiceInfo.FOREGROUND_SERVICE_TYPE_LOCATION or ServiceInfo.FOREGROUND_SERVICE_TYPE_DATA_SYNC)
    }

    private suspend fun initSockets() = socketMutex.withLock {
        closeSocketsInternal()
        try {
            zmqContext = ZMQ.context(1)
            pushSocket = zmqContext?.socket(SocketType.PUSH)
            pullSocket = zmqContext?.socket(SocketType.PULL)

            pushSocket?.sendTimeOut = 3000 
            pushSocket?.linger = 0

            pushSocket?.connect("tcp://${ServerConfig.serverIp}:5558")
            pullSocket?.connect("tcp://${ServerConfig.serverIp}:5559")

            lastSuccessfulSend = System.currentTimeMillis()
            Log.d(tag, "Sockets connected to ${ServerConfig.serverIp}")
        } catch (e: Exception) {
            Log.e(tag, "Socket init error: ${e.message}")
        }
    }

    private suspend fun reconnect() {
        Log.w(tag, "Reconnecting...")
        initSockets()
    }

    private fun closeSocketsInternal() {
        try {
            pushSocket?.close()
            pullSocket?.close()
            zmqContext?.term()
        } catch (_: Exception) {}
        pushSocket = null
        pullSocket = null
        zmqContext = null
    }

    private fun setupLocationUpdates() {
        val locationRequest = LocationRequest.Builder(Priority.PRIORITY_HIGH_ACCURACY, 100)
            .setMinUpdateIntervalMillis(100)
            .build()

        locationCallback = object : LocationCallback() {
            override fun onLocationResult(locationResult: LocationResult) {
                val loc = locationResult.lastLocation ?: return
                currentLocation = LocationData(loc.latitude, loc.longitude, loc.altitude, loc.time, loc.accuracy)
                currentLocExtras["speed"] = loc.speed
                currentLocExtras["bearing"] = loc.bearing
            }
        }

        if (ActivityCompat.checkSelfPermission(this, Manifest.permission.ACCESS_FINE_LOCATION) == PackageManager.PERMISSION_GRANTED) {
            fusedLocationClient.requestLocationUpdates(locationRequest, locationCallback, Looper.getMainLooper())
        }
    }

    private fun listenTelephony() {
        val tm = getSystemService(TELEPHONY_SERVICE) as TelephonyManager
        if (ActivityCompat.checkSelfPermission(this, Manifest.permission.ACCESS_FINE_LOCATION) != PackageManager.PERMISSION_GRANTED) return

        tm.registerTelephonyCallback(mainExecutor, object : TelephonyCallback(), TelephonyCallback.CellInfoListener, TelephonyCallback.SignalStrengthsListener {
            override fun onCellInfoChanged(cellInfo: List<CellInfo>) {
                latestCellInfo = cellInfo
                serviceScope.launch {
                    collectAndSendData()
                }
            }

            override fun onSignalStrengthsChanged(signalStrength: SignalStrength) {
                // Trigger immediate update on signal change
                serviceScope.launch {
                    collectAndSendData()
                }
            }
        })
    }

    private fun startDataCollection() {
        serviceScope.launch {
            while (isActive) {
                if (!(wakeLock?.isHeld ?: false)) {
                    wakeLock?.acquire(10 * 60 * 1000L)
                }
                try {
                    collectAndSendData()
                } catch (e: Exception) {
                    Log.e(tag, "Loop error: ${e.message}")
                }
                val interval = if (latestCellInfo.size > 3) 1000L else 500L
                delay(interval)
            }
        }
    }

    private fun pollCellInfo() {
        // Redundant polling removed as we use TelephonyCallback
    }

    private suspend fun collectAndSendData() {
        val telephonyInfo = getTelephonyInfo()

        // Detect Cell Handover and reset smoothing history
        val currentPrimary = telephonyInfo.firstOrNull { it["isRegistered"] == true }
        val primaryKey = currentPrimary?.let { 
            "${it["type"]}_${it["cellId"] ?: it["nci"] ?: ""}_${it["earfcn"] ?: it["nrarfcn"] ?: it["arfcn"]}"
        }
        if (primaryKey != lastPrimaryCellKey) {
            pathLossHistory.clear()
            kalmanFilters.clear()
            lastPrimaryCellKey = primaryKey
        }

        val data = mutableMapOf<String, Any?>(
            "type" to "combined",
            "timestamp" to System.currentTimeMillis(),
            "device_orientation" to azimuthValue,
            "pressure_hpa" to pressureValue
        )
        if (filterLocation) {
            val locMap = mutableMapOf<String, Any?>()
            currentLocation?.let {
                locMap["latitude"] = it.latitude
                locMap["longitude"] = it.longitude

                if (smoothGps) {
                    locMap["lat_smoothed"] = latFilter.filter(it.latitude)
                    locMap["lon_smoothed"] = lonFilter.filter(it.longitude)
                }

                locMap["altitude"] = it.altitude
                locMap["time"] = it.time
                locMap["accuracy"] = it.accuracy
                locMap.putAll(currentLocExtras)
            }
            data["location"] = locMap.ifEmpty { null }
        }
        if (filterTelephony) data["telephony"] = telephonyInfo
        if (filterNetwork) data["networkUsage"] = getNetworkUsage()

        val json = gson.toJson(data)

        // Add to buffer for reliability
        sendBuffer.addLast(json)
        if (sendBuffer.size > MAX_BUFFER_SIZE) flushBufferToDisk()

        processSendBuffer()

        saveToFile(data)
        TelephonyDataBus.emit(json)
    }

    private suspend fun processSendBuffer() {
        if (sendBuffer.isEmpty()) return

        socketMutex.withLock {
            val iterator = sendBuffer.iterator()
            while (iterator.hasNext()) {
                val item = iterator.next()
                try {
                    val success = pushSocket?.send(item) ?: false
                    if (success) {
                        iterator.remove()
                        lastSuccessfulSend = System.currentTimeMillis()
                        totalPacketsSent++
                    } else {
                        // Socket full or disconnected
                        break 
                    }
                } catch (e: Exception) {
                    Log.e(tag, "Buffer send error: ${e.message}")
                    break
                }
            }
        }

        val cellsCount = latestCellInfo.size
        if (sendBuffer.isEmpty()) {
            updateNotification("Sending data...", totalPacketsSent, cellsCount)
        } else {
            errorCount++
            updateNotification("Buffering (${sendBuffer.size})", totalPacketsSent, cellsCount)
            if (System.currentTimeMillis() - lastSuccessfulSend > 5000) {
                reconnect()
            }
        }
    }

    private fun flushBufferToDisk() {
        try {
            logFile.appendText(sendBuffer.joinToString("\n") + "\n")
            sendBuffer.clear()
        } catch (_: Exception) {}
    }

    private fun getTelephonyInfo(): List<Map<String, Any?>> {
        val list = mutableListOf<Map<String, Any?>>()
        val cellInfoList = latestCellInfo

        cellInfoList.forEach { info ->
            val map = mutableMapOf<String, Any?>()
            map["isRegistered"] = info.isRegistered

            when (info) {
                is CellInfoLte -> {
                    val id = info.cellIdentity
                    val ss = info.cellSignalStrength
                    val earfcn = if (id.earfcn != Int.MAX_VALUE) id.earfcn else -1
                    val band = id.bands.firstOrNull() ?: 0
                    val freq = calculateLteFreq(earfcn, band)

                    map["type"] = "LTE"
                    map["pci"] = if (id.pci != Int.MAX_VALUE) id.pci else -1
                    map["earfcn"] = earfcn
                    map["band"] = band
                    map["frequency"] = freq
                    map["tac"] = if (id.tac != Int.MAX_VALUE) id.tac.toString() else ""
                    map["cellId"] = if (id.ci != Int.MAX_VALUE) id.ci.toString() else ""
                    map["mcc"] = id.mccString ?: ""
                    map["mnc"] = id.mncString ?: ""

                    map["rsrp"] = if (ss.rsrp != Int.MAX_VALUE) ss.rsrp else -140
                    map["rsrq"] = if (ss.rsrq != Int.MAX_VALUE) ss.rsrq else 0
                    map["rssi"] = if (ss.rssi != Int.MAX_VALUE) ss.rssi else if (ss.dbm != Int.MAX_VALUE) ss.dbm else -140
                    map["rssnr"] = if (ss.rssnr != Int.MAX_VALUE) ss.rssnr else 0
                    map["sinr"] = calculateSinr(ss.rssnr, ss.rsrq)
                    map["cqi"] = if (ss.cqi != Int.MAX_VALUE) ss.cqi else 0
                    map["asuLevel"] = ss.asuLevel
                    map["timingAdvance"] = if (ss.timingAdvance != Int.MAX_VALUE) ss.timingAdvance else 0

                    if (freq > 0) {
                        map["pathLossModels"] = calculatePathLoss(freq, info)
                    }
                }

                is CellInfoNr -> {
                    val id = info.cellIdentity as CellIdentityNr
                    val ss = info.cellSignalStrength as CellSignalStrengthNr
                    val nrarfcn = if (id.nrarfcn != Int.MAX_VALUE) id.nrarfcn else -1
                    val band = id.bands.firstOrNull() ?: 0
                    val freq = calculateNrFreq(nrarfcn)

                    map["type"] = "NR"
                    map["pci"] = if (id.pci != Int.MAX_VALUE) id.pci else -1
                    map["nrarfcn"] = nrarfcn
                    map["band"] = band
                    map["frequency"] = freq
                    map["nci"] = if (id.nci != Long.MAX_VALUE) id.nci.toString() else ""
                    map["tac"] = if (id.tac != Int.MAX_VALUE) id.tac.toString() else ""
                    map["mcc"] = id.mccString ?: ""
                    map["mnc"] = id.mncString ?: ""

                    map["rsrp"] = if (ss.ssRsrp != Int.MAX_VALUE) ss.ssRsrp else -140
                    map["rsrq"] = if (ss.ssRsrq != Int.MAX_VALUE) ss.ssRsrq else 0
                    map["sinr"] = if (ss.ssSinr != Int.MAX_VALUE) ss.ssSinr else 0
                    map["timingAdvance"] = if (ss.timingAdvanceMicros != Int.MAX_VALUE) ss.timingAdvanceMicros else 0

                    if (freq > 0) {
                        map["pathLossModels"] = calculatePathLoss(freq, info)
                    }
                }

                is CellInfoGsm -> {
                    val id = info.cellIdentity
                    val ss = info.cellSignalStrength
                    val arfcn = if (id.arfcn != Int.MAX_VALUE) id.arfcn else -1
                    val freq = calculateGsmFreq(arfcn)

                    map["type"] = "GSM"
                    map["arfcn"] = arfcn
                    map["frequency"] = freq
                    map["bsic"] = if (id.bsic != Int.MAX_VALUE) id.bsic else -1
                    map["lac"] = if (id.lac != Int.MAX_VALUE) id.lac else -1
                    map["psc"] = -1
                    map["rssi"] = if (ss.dbm != Int.MAX_VALUE) ss.dbm else 0
                    map["dbm"] = ss.dbm
                    map["mcc"] = id.mccString ?: ""
                    map["mnc"] = id.mncString ?: ""
                    map["cellId"] = if (id.cid != Int.MAX_VALUE) id.cid.toString() else ""
                    map["timingAdvance"] = if (ss.timingAdvance != Int.MAX_VALUE) ss.timingAdvance else 0

                    if (freq > 0) {
                        map["pathLossModels"] = calculatePathLoss(freq, info)
                    }
                }

                else -> return@forEach
            }

            if (map.containsKey("type")) list.add(map)
        }
        return list
    }

    private fun calculateLteFreq(earfcn: Int, band: Int): Double {
        if (earfcn == -1) return 0.0
        return when (band) {
            1 -> 2110.0 + 0.1 * (earfcn - 0)
            3 -> 1805.0 + 0.1 * (earfcn - 1200)
            7 -> 2620.0 + 0.1 * (earfcn - 2750)
            8 -> 925.0 + 0.1 * (earfcn - 3450)
            20 -> 791.0 + 0.1 * (earfcn - 6150)
            38 -> 2570.0 + 0.1 * (earfcn - 37750)
            40 -> 2300.0 + 0.1 * (earfcn - 38650)
            else -> {
                when (earfcn) {
                    in 0..599 -> 2110.0 + earfcn * 0.1
                    in 1200..1949 -> 1805.0 + (earfcn - 1200) * 0.1
                    else -> 0.0
                }
            }
        }
    }

    private fun calculateNrFreq(nrarfcn: Int): Double {
        return if (nrarfcn < 600000) nrarfcn * 0.005 else 3000.0 + (nrarfcn - 600000) * 0.015
    }

    private fun calculateGsmFreq(arfcn: Int): Double {
        return when (arfcn) {
            in 1..124 -> 935.0 + arfcn * 0.2
            in 512..885 -> 1805.2 + (arfcn - 512) * 0.2
            else -> 0.0
        }
    }

    private fun calculateSinr(rssnr: Int, rsrq: Int): Double {
        val sinr = if (rssnr != Int.MAX_VALUE && rssnr != Int.MIN_VALUE) {
            rssnr / 10.0
        } else {
            if (rsrq != Int.MAX_VALUE) (rsrq + 20).toDouble() else 0.0
        }
        return sinr.coerceIn(-30.0, 40.0)
    }

    private fun calculatePathLoss(freqMHz: Double, info: CellInfo): Map<String, Double> {
        val hb = 30.0

        // Barometric formula for altitude calculation (ISA)
        val hm = if (pressureValue > 300f) {
            val calculatedHm = 44330.0 * (1.0 - (pressureValue / 1013.25).pow(0.1903))
            calculatedHm.coerceIn(1.0, 50.0)
        } else {
            1.5
        }

        // Get RSRP for models and distance fallback
        val rsrp = when (info) {
            is CellInfoLte -> info.cellSignalStrength.rsrp
            is CellInfoNr -> (info.cellSignalStrength as CellSignalStrengthNr).ssRsrp
            is CellInfoGsm -> info.cellSignalStrength.dbm
            else -> Int.MAX_VALUE
        }

        // Filter out extremely poor signals to avoid processing garbage data
        if (rsrp == Int.MAX_VALUE || rsrp < -130) return emptyMap()

        val taKm = when (info) {
            is CellInfoLte -> {
                val ta = info.cellSignalStrength.timingAdvance
                if (ta != Int.MAX_VALUE && ta > 0) ta.toDouble() * 0.078 else -1.0
            }
            is CellInfoNr -> {
                val taMicros = (info.cellSignalStrength as CellSignalStrengthNr).timingAdvanceMicros
                // c ≈ 3e8 м/с → 0.3 км/мкс
                // d = (TA * c) / 2
                if (taMicros != Int.MAX_VALUE && taMicros > 0) (taMicros.toDouble() * 0.15).coerceIn(0.1, 10.0) else -1.0
            }
            is CellInfoGsm -> {
                val ta = info.cellSignalStrength.timingAdvance
                if (ta != Int.MAX_VALUE && ta > 0) ta.toDouble() * 0.55 else -1.0
            }
            else -> -1.0
        }

        // Distance Refinement: TA is jittery, so we use a distance fallback from RSRP
        val txPower = when {
            freqMHz < 1000 -> 46.0
            freqMHz < 2000 -> 43.0
            else -> 40.0
        }

        val d = if (taKm > 0) {
            max(0.5, taKm).coerceIn(0.5, 20.0)
        } else {
            // Distance estimation from RSRP (Inverse FSPL) as fallback
            val plFromRsrp = txPower - rsrp
            10.0.pow((plFromRsrp - 32.44 - 20 * log10(freqMHz)) / 20.0).coerceIn(0.5, 20.0)
        }

        val ahrUrban = (1.1 * log10(freqMHz) - 0.7) * hm - (1.56 * log10(freqMHz) - 0.8)

        val res = mutableMapOf<String, Double>()
        res["wavelength"] = 299.79 / freqMHz
        res["elevation_hm"] = hm

        // Free Space Path Loss (Sanity Check / Reference)
        val fspl = 32.44 + 20 * log10(freqMHz) + 20 * log10(d)
        res["loss_fspl"] = fspl

        val mainLoss = when {
            freqMHz <= 1500 -> {
                // Okumura-Hata (< 1500 MHz)
                69.55 + 26.16 * log10(freqMHz) - 13.82 * log10(hb) - ahrUrban + (44.9 - 6.55 * log10(hb)) * log10(d)
            }
            freqMHz <= 2000 -> {
                // COST-231 Hata (1500 - 2000 MHz)
                val cm = 3.0 // Urban environment constant
                46.3 + 33.9 * log10(freqMHz) - 13.82 * log10(hb) - ahrUrban + (44.9 - 6.55 * log10(hb)) * log10(d) + cm
            }
            else -> {
                // High frequency fallback (beyond standard Hata/COST-231 range)
                // Using FSPL + 20 dB as a standard urban clutter margin
                fspl + 20.0 
            }
        }

        val clutterLoss = when {
            freqMHz < 1000 -> 10
            freqMHz < 2000 -> 15
            else -> 20
        }

        val adjustedLoss = mainLoss + clutterLoss

        if (freqMHz <= 1500) res["loss_hata"] = mainLoss
        else if (freqMHz <= 2000) res["loss_cost231"] = mainLoss
        else res["loss_fallback"] = mainLoss

        res["loss_adjusted"] = adjustedLoss

        // Weighted Hybrid Model for smoother transitions
        // Near field (< 1km): Mostly FSPL
        // Transition (1-5km): Weighted average
        // Far field (> 5km): Mostly empirical models (Hata/COST-231)
        val hybrid = when {
            d < 1.0 -> fspl
            d < 5.0 -> (fspl * 0.6 + mainLoss * 0.4)
            else -> (fspl * 0.3 + mainLoss * 0.7)
        }

        // Median Filter for Noise Reduction
        val cellKey = when(info) {
            is CellInfoLte -> "LTE_${info.cellIdentity.pci}_${info.cellIdentity.earfcn}"
            is CellInfoNr -> "NR_${(info.cellIdentity as CellIdentityNr).pci}_${(info.cellIdentity as CellIdentityNr).nrarfcn}"
            is CellInfoGsm -> "GSM_${info.cellIdentity.cid}_${info.cellIdentity.arfcn}"
            else -> "UNKNOWN"
        }
        val smoothedMedian = getSmoothedLoss(cellKey, hybrid)

        // Final Kalman stage for "engineering-grade" stability
        val kalman = kalmanFilters.getOrPut(cellKey) { KalmanFilter(q = 0.05, r = if (d < 2) 0.5 else 2.0) }
        res["loss_hybrid"] = kalman.filter(smoothedMedian)

        return res
    }

    private fun getSmoothedLoss(cellKey: String, value: Double): Double {
        val history = pathLossHistory.getOrPut(cellKey) { ArrayDeque<Double>() }
        history.addLast(value)
        if (history.size > 5) history.removeFirst()
        val sortedList = history.toList().sorted()
        return sortedList[sortedList.size / 2]
    }

    private fun getNetworkUsage(): NetworkUsageData {
        val nsm = getSystemService(NETWORK_STATS_SERVICE) as NetworkStatsManager
        var totalSent = 0L
        var totalReceived = 0L

        try {
            val now = System.currentTimeMillis()
            val mobileBucket = nsm.querySummaryForDevice(NetworkCapabilities.TRANSPORT_CELLULAR, null, 0, now)
            totalSent += mobileBucket.txBytes
            totalReceived += mobileBucket.rxBytes

            try {
                val wifiBucket = nsm.querySummaryForDevice(NetworkCapabilities.TRANSPORT_WIFI, null, 0, now)
                totalSent += wifiBucket.txBytes
                totalReceived += wifiBucket.rxBytes
            } catch (_: Exception) {}

            lastNetworkData?.let {
                if (totalSent < it.totalBytesSent) totalSent = it.totalBytesSent
                if (totalReceived < it.totalBytesReceived) totalReceived = it.totalBytesReceived
            }

            var topApps: List<AppUsage>? = lastNetworkData?.topApps
            if (System.currentTimeMillis() - lastNetworkQueryTime > 15000) {
                topApps = queryTopApps(nsm)
                lastNetworkQueryTime = System.currentTimeMillis()
            }

            val result = NetworkUsageData(totalSent, totalReceived, topApps)
            lastNetworkData = result
            return result
        } catch (e: Exception) {
            Log.e(tag, "Error getting network stats: ${e.message}")
            return lastNetworkData ?: NetworkUsageData(0, 0, null)
        }
    }

    private fun queryTopApps(nsm: NetworkStatsManager): List<AppUsage> {
        val appList = mutableListOf<AppUsage>()
        val pm = packageManager
        val startTime = System.currentTimeMillis() - 24 * 60 * 60 * 1000
        val now = System.currentTimeMillis()

        try {
            val stats = nsm.querySummary(NetworkCapabilities.TRANSPORT_CELLULAR, null, startTime, now)
            val outBucket = NetworkStats.Bucket()
            val tempUsageMap = mutableMapOf<Int, Long>()
            while (stats.hasNextBucket()) {
                stats.getNextBucket(outBucket)
                tempUsageMap[outBucket.uid] = (tempUsageMap[outBucket.uid] ?: 0L) + outBucket.txBytes + outBucket.rxBytes
            }
            stats.close()

            tempUsageMap.forEach { (uid, bytes) ->
                if (bytes > 1024 * 1024) {
                    val name = pm.getNameForUid(uid) ?: "uid_$uid"
                    if (name != "android" && !name.contains("com.android.providers.media")) {
                        appList.add(AppUsage(name, bytes))
                    }
                }
            }
            return appList.sortedByDescending { it.bytes }.take(10)
        } catch (_: Exception) {}
        return emptyList()
    }

    private fun startConnectionMonitor() {
        serviceScope.launch {
            while (isActive) {
                if (System.currentTimeMillis() - lastSuccessfulSend > 20000) {
                    Log.w(tag, "Connection lost. Reconnecting...")
                    reconnect()
                }
                delay(10000)
            }
        }
    }

    private fun startCommandListener() {
        serviceScope.launch {
            while (isActive) {
                try {
                    val rawCmd = socketMutex.withLock {
                        pullSocket?.recvStr(ZMQ.DONTWAIT)
                    }
                    rawCmd?.let { jsonStr ->
                        try {
                            val cmdData = gson.fromJson(jsonStr, Map::class.java)
                            val cmd = cmdData["cmd"] as? String ?: ""

                            when (cmd) {
                                "SET_DELAY" -> {
                                    val value = (cmdData["value"] as? Double)?.toLong() ?: 500L
                                    dataCollectionDelay = value.coerceIn(100, 10000)
                                    Log.d(tag, "Command: Collection delay set to $dataCollectionDelay ms")
                                }
                                "TOGGLE_FILTER" -> {
                                    val target = cmdData["target"] as? String
                                    val state = cmdData["state"] as? Boolean ?: true
                                    when (target) {
                                        "location" -> filterLocation = state
                                        "telephony" -> filterTelephony = state
                                        "network" -> filterNetwork = state
                                    }
                                }
                                "SET_GPS_SMOOTHING" -> {
                                    smoothGps = cmdData["state"] as? Boolean ?: true
                                }
                                "RESET_HISTORY" -> {
                                    pathLossHistory.clear()
                                    kalmanFilters.clear()
                                    Log.d(tag, "Command: Histories reset")
                                }
                                "RECONNECT" -> {
                                    reconnect()
                                }
                            }
                        } catch (e: Exception) {
                            // Fallback for legacy string commands
                            when (jsonStr) {
                                "FILTER_LOCATION_ON" -> filterLocation = true
                                "FILTER_LOCATION_OFF" -> filterLocation = false
                                "FILTER_TELEPHONY_ON" -> filterTelephony = true
                                "FILTER_TELEPHONY_OFF" -> filterTelephony = false
                            }
                        }
                    }
                } catch (_: Exception) {}
                delay(1000)
            }
        }
    }

    private fun saveToFile(data: Map<String, Any?>) {
        try { logFile.appendText(gson.toJson(data) + "\n") } catch (_: Exception) {}
    }

    private fun acquireWakeLock() {
        val pm = getSystemService(POWER_SERVICE) as PowerManager
        wakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "TelephonyService::WakeLock")
        wakeLock?.acquire(10 * 60 * 1000L)
    }

    private fun createNotificationChannel() {
        val serviceChannel = NotificationChannel(channelId, "Telephony Service Channel", NotificationManager.IMPORTANCE_HIGH)
        val manager = getSystemService(NotificationManager::class.java)
        manager?.createNotificationChannel(serviceChannel)
    }

    override fun onSensorChanged(event: SensorEvent?) {
        when (event?.sensor?.type) {
            Sensor.TYPE_PRESSURE -> pressureValue = event.values[0]
            Sensor.TYPE_ROTATION_VECTOR -> {
                val rotationMatrix = FloatArray(9)
                SensorManager.getRotationMatrixFromVector(rotationMatrix, event.values)
                val orientation = FloatArray(3)
                SensorManager.getOrientation(rotationMatrix, orientation)
                // convert to degrees and normalize to [0, 360]
                var azimuth = Math.toDegrees(orientation[0].toDouble()).toFloat()
                if (azimuth < 0) azimuth += 360f
                azimuthValue = azimuth
            }
        }
    }

    override fun onAccuracyChanged(sensor: Sensor?, accuracy: Int) {}

    override fun onDestroy() {
        sensorManager.unregisterListener(this)
        serviceJob.cancel()
        if (::locationCallback.isInitialized) {
            fusedLocationClient.removeLocationUpdates(locationCallback)
        }
        runBlocking {
            socketMutex.withLock {
                closeSocketsInternal()
            }
        }
        wakeLock?.release()
        super.onDestroy()
    }

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int = START_STICKY
    override fun onBind(intent: Intent?): IBinder? = null
}

package com.example.visprog

import android.Manifest
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.Service
import android.app.usage.NetworkStats
import android.app.usage.NetworkStatsManager
import android.content.Intent
import android.content.pm.PackageManager
import android.content.pm.ServiceInfo
import android.hardware.Sensor
import android.hardware.SensorEvent
import android.hardware.SensorEventListener
import android.hardware.SensorManager
import android.net.ConnectivityManager
import android.net.NetworkCapabilities
import android.os.Environment
import android.os.IBinder
import android.os.Looper
import android.os.PowerManager
import android.telephony.CellIdentityNr
import android.telephony.CellInfo
import android.telephony.CellInfoGsm
import android.telephony.CellInfoLte
import android.telephony.CellInfoNr
import android.telephony.CellSignalStrengthNr
import android.telephony.SignalStrength
import android.telephony.TelephonyCallback
import android.telephony.TelephonyManager
import android.util.Log
import androidx.core.app.ActivityCompat
import androidx.core.app.NotificationCompat
import com.example.visprog.config.ServerConfig
import com.example.visprog.data.LocationData
import com.example.visprog.utils.TelephonyDataBus
import com.google.android.gms.location.FusedLocationProviderClient
import com.google.android.gms.location.LocationCallback
import com.google.android.gms.location.LocationRequest
import com.google.android.gms.location.LocationResult
import com.google.android.gms.location.LocationServices
import com.google.android.gms.location.Priority
import com.google.gson.Gson
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.delay
import kotlinx.coroutines.isActive
import kotlinx.coroutines.launch
import kotlinx.coroutines.runBlocking
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock
import org.zeromq.SocketType
import org.zeromq.ZMQ
import java.io.File
import java.util.ArrayDeque
import kotlin.math.log10
import kotlin.math.max
import kotlin.math.pow
import kotlin.math.roundToInt

class TelephonyService : Service(), SensorEventListener {
    private val tag = "TelephonyService"
    private val channelId = "telephony_service_channel"
    private val gson = Gson()

    private lateinit var sensorManager: SensorManager
    private var pressureValue: Float = 0f
    private var azimuthValue: Float = 0f

    private lateinit var fusedLocationClient: FusedLocationProviderClient
    private lateinit var locationCallback: LocationCallback
    private var currentLocation: LocationData? = null
    private val currentLocExtras = mutableMapOf<String, Any>()

    private var zmqContext: ZMQ.Context? = null
    private var pushSocket: ZMQ.Socket? = null
    private var pullSocket: ZMQ.Socket? = null
    private val socketMutex = Mutex()
    private var lastSuccessfulSend: Long = System.currentTimeMillis()

    private val serviceJob = SupervisorJob()
    private val serviceScope = CoroutineScope(Dispatchers.IO + serviceJob)
    private var wakeLock: PowerManager.WakeLock? = null
    private lateinit var logFile: File

    private var filterLocation = true
    private var filterTelephony = true
    private var filterNetwork = true
    private var smoothGps = true
    private var dataCollectionDelay = 500L

    private var latestCellInfo: List<CellInfo> = emptyList()
    private var totalPacketsSent = 0
    private var lastNotificationUpdateTime = 0L

    private var lastNetworkData: NetworkUsageData? = null
    private var lastNetworkQueryTime: Long = 0L

    private val pathLossHistory = mutableMapOf<String, ArrayDeque<Double>>()
    private val kalmanFilters = mutableMapOf<String, KalmanFilter>()
    private val latFilter = KalmanFilter(q = 0.000001, r = 0.00001) // High precision for GPS
    private val lonFilter = KalmanFilter(q = 0.000001, r = 0.00001)
    private var lastPrimaryCellKey: String? = null

    private val sendBuffer = ArrayDeque<String>()
    private val MAX_BUFFER_SIZE = 100

    class KalmanFilter(private val q: Double = 0.1, private val r: Double = 1.0) {
        private var x = 0.0 // State
        private var p = 1.0 // Covariance
        private var initialized = false

        fun filter(measurement: Double): Double {
            if (!initialized) {
                x = measurement
                initialized = true
                return x
            }
            // Prediction
            p += q
            // Update
            val k = p / (p + r)
            x += k * (measurement - x)
            p *= (1 - k)
            return x
        }
    }

    data class NetworkUsageData(val totalBytesSent: Long, val totalBytesReceived: Long, val topApps: List<AppUsage>? = null)
    data class AppUsage(val packageName: String, val bytes: Long)

    private fun isNetworkCellular(): Boolean {
        val cm = getSystemService(CONNECTIVITY_SERVICE) as ConnectivityManager
        val nc = cm.activeNetwork ?: return false
        val caps = cm.getNetworkCapabilities(nc) ?: return false
        return caps.hasTransport(NetworkCapabilities.TRANSPORT_CELLULAR)
    }

    override fun onCreate() {
        super.onCreate()
        createNotificationChannel()
        updateNotification("Service started", 0, 0)

        fusedLocationClient = LocationServices.getFusedLocationProviderClient(this)
        sensorManager = getSystemService(SENSOR_SERVICE) as SensorManager
        sensorManager.getDefaultSensor(Sensor.TYPE_PRESSURE)?.let {
            sensorManager.registerListener(this, it, SensorManager.SENSOR_DELAY_NORMAL)
        }
        sensorManager.getDefaultSensor(Sensor.TYPE_ROTATION_VECTOR)?.let {
            sensorManager.registerListener(this, it, SensorManager.SENSOR_DELAY_NORMAL)
        }

        val documentsDir = getExternalFilesDir(Environment.DIRECTORY_DOCUMENTS) ?: filesDir
        if (!documentsDir.exists()) documentsDir.mkdirs()
        logFile = File(documentsDir, "telephony_log.json")

        setupLocationUpdates()
        listenTelephony()

        serviceScope.launch {
            initSockets()
            startDataCollection()
            startConnectionMonitor()
            startCommandListener()
        }
        acquireWakeLock()
    }

    private var errorCount = 0

    private fun updateNotification(text: String, count: Int, cellsCount: Int) {
        val now = System.currentTimeMillis()
        if (now - lastNotificationUpdateTime < 1000 && count != 0) return
        lastNotificationUpdateTime = now

        val notification = NotificationCompat.Builder(this, channelId)
            .setContentTitle("Telephony Tracking: $text")
            .setContentText("Sent: $totalPacketsSent | Errors: $errorCount | Cells: $cellsCount")
            .setSmallIcon(R.drawable.ic_launcher_foreground)
            .setPriority(NotificationCompat.PRIORITY_HIGH)
            .setOngoing(true)
            .setOnlyAlertOnce(true)
            .build()

        startForeground(1, notification, ServiceInfo.FOREGROUND_SERVICE_TYPE_LOCATION or ServiceInfo.FOREGROUND_SERVICE_TYPE_DATA_SYNC)
    }

    private suspend fun initSockets() = socketMutex.withLock {
        closeSocketsInternal()
        try {
            zmqContext = ZMQ.context(1)
            pushSocket = zmqContext?.socket(SocketType.PUSH)
            pullSocket = zmqContext?.socket(SocketType.PULL)

            pushSocket?.sendTimeOut = 3000 
            pushSocket?.linger = 0

            pushSocket?.connect("tcp://${ServerConfig.serverIp}:5558")
            pullSocket?.connect("tcp://${ServerConfig.serverIp}:5559")

            lastSuccessfulSend = System.currentTimeMillis()
            Log.d(tag, "Sockets connected to ${ServerConfig.serverIp}")
        } catch (e: Exception) {
            Log.e(tag, "Socket init error: ${e.message}")
        }
    }

    private suspend fun reconnect() {
        Log.w(tag, "Reconnecting...")
        initSockets()
    }

    private fun closeSocketsInternal() {
        try {
            pushSocket?.close()
            pullSocket?.close()
            zmqContext?.term()
        } catch (_: Exception) {}
        pushSocket = null
        pullSocket = null
        zmqContext = null
    }

    private fun setupLocationUpdates() {
        val locationRequest = LocationRequest.Builder(Priority.PRIORITY_HIGH_ACCURACY, 100)
            .setMinUpdateIntervalMillis(100)
            .build()

        locationCallback = object : LocationCallback() {
            override fun onLocationResult(locationResult: LocationResult) {
                val loc = locationResult.lastLocation ?: return
                currentLocation = LocationData(loc.latitude, loc.longitude, loc.altitude, loc.time, loc.accuracy)
                currentLocExtras["speed"] = loc.speed
                currentLocExtras["bearing"] = loc.bearing
            }
        }

        if (ActivityCompat.checkSelfPermission(this, Manifest.permission.ACCESS_FINE_LOCATION) == PackageManager.PERMISSION_GRANTED) {
            fusedLocationClient.requestLocationUpdates(locationRequest, locationCallback, Looper.getMainLooper())
        }
    }

    private fun listenTelephony() {
        val tm = getSystemService(TELEPHONY_SERVICE) as TelephonyManager
        if (ActivityCompat.checkSelfPermission(this, Manifest.permission.ACCESS_FINE_LOCATION) != PackageManager.PERMISSION_GRANTED) return

        tm.registerTelephonyCallback(mainExecutor, object : TelephonyCallback(), TelephonyCallback.CellInfoListener, TelephonyCallback.SignalStrengthsListener {
            override fun onCellInfoChanged(cellInfo: List<CellInfo>) {
                latestCellInfo = cellInfo
                serviceScope.launch {
                    collectAndSendData()
                }
            }

            override fun onSignalStrengthsChanged(signalStrength: SignalStrength) {
                // Trigger immediate update on signal change
                serviceScope.launch {
                    collectAndSendData()
                }
            }
        })
    }

    private fun startDataCollection() {
        serviceScope.launch {
            while (isActive) {
                if (!(wakeLock?.isHeld ?: false)) {
                    wakeLock?.acquire(10 * 60 * 1000L)
                }
                try {
                    collectAndSendData()
                } catch (e: Exception) {
                    Log.e(tag, "Loop error: ${e.message}")
                }
                val interval = if (latestCellInfo.size > 3) 1000L else 500L
                delay(interval)
            }
        }
    }

    private fun pollCellInfo() {
        // Redundant polling removed as we use TelephonyCallback
    }

    private suspend fun collectAndSendData() {
        val telephonyInfo = getTelephonyInfo()

        // Detect Cell Handover and reset smoothing history
        val currentPrimary = telephonyInfo.firstOrNull { it["isRegistered"] == true }
        val primaryKey = currentPrimary?.let { 
            "${it["type"]}_${it["cellId"] ?: it["nci"] ?: ""}_${it["earfcn"] ?: it["nrarfcn"] ?: it["arfcn"]}"
        }
        if (primaryKey != lastPrimaryCellKey) {
            pathLossHistory.clear()
            kalmanFilters.clear()
            lastPrimaryCellKey = primaryKey
        }

        val data = mutableMapOf<String, Any?>(
            "type" to "combined",
            "timestamp" to System.currentTimeMillis(),
            "device_orientation" to azimuthValue,
            "pressure_hpa" to pressureValue
        )
        if (filterLocation) {
            val locMap = mutableMapOf<String, Any?>()
            currentLocation?.let {
                locMap["latitude"] = it.latitude
                locMap["longitude"] = it.longitude

                if (smoothGps) {
                    locMap["lat_smoothed"] = latFilter.filter(it.latitude)
                    locMap["lon_smoothed"] = lonFilter.filter(it.longitude)
                }

                locMap["altitude"] = it.altitude
                locMap["time"] = it.time
                locMap["accuracy"] = it.accuracy
                locMap.putAll(currentLocExtras)
            }
            data["location"] = locMap.ifEmpty { null }
        }
        if (filterTelephony) data["telephony"] = telephonyInfo
        if (filterNetwork) data["networkUsage"] = getNetworkUsage()

        val json = gson.toJson(data)

        // Add to buffer for reliability
        sendBuffer.addLast(json)
        if (sendBuffer.size > MAX_BUFFER_SIZE) flushBufferToDisk()

        processSendBuffer()

        saveToFile(data)
        TelephonyDataBus.emit(json)
    }

    private suspend fun processSendBuffer() {
        if (pushSocket == null || !isNetworkCellular()) return
        if (sendBuffer.isEmpty()) return

        socketMutex.withLock {
            val iterator = sendBuffer.iterator()
            while (iterator.hasNext()) {
                val item = iterator.next()
                try {
                    val success = pushSocket?.send(item) ?: false
                    if (success) {
                        iterator.remove()
                        lastSuccessfulSend = System.currentTimeMillis()
                        totalPacketsSent++
                    } else {
                        // Socket full or disconnected
                        break 
                    }
                } catch (e: Exception) {
                    Log.e(tag, "Buffer send error: ${e.message}")
                    break
                }
            }
        }

        val cellsCount = latestCellInfo.size
        if (sendBuffer.isEmpty()) {
            updateNotification("Sending data...", totalPacketsSent, cellsCount)
        } else {
            errorCount++
            updateNotification("Buffering (${sendBuffer.size})", totalPacketsSent, cellsCount)
            if (System.currentTimeMillis() - lastSuccessfulSend > 5000) {
                reconnect()
            }
        }
    }

    private fun flushBufferToDisk() {
        try {
            logFile.appendText(sendBuffer.joinToString("\n") + "\n")
            sendBuffer.clear()
        } catch (_: Exception) {}
    }

    private fun getTelephonyInfo(): List<Map<String, Any?>> {
        val list = mutableListOf<Map<String, Any?>>()
        val cellInfoList = latestCellInfo

        cellInfoList.forEach { info ->
            val map = mutableMapOf<String, Any?>()
            map["isRegistered"] = info.isRegistered

            when (info) {
                is CellInfoLte -> {
                    val id = info.cellIdentity
                    val ss = info.cellSignalStrength
                    val earfcn = if (id.earfcn != Int.MAX_VALUE) id.earfcn else -1
                    val band = id.bands.firstOrNull() ?: 0
                    val freq = calculateLteFreq(earfcn, band)

                    map["type"] = "LTE"
                    map["pci"] = if (id.pci != Int.MAX_VALUE) id.pci else -1
                    map["earfcn"] = earfcn
                    map["band"] = band
                    map["frequency"] = freq
                    map["tac"] = if (id.tac != Int.MAX_VALUE) id.tac.toString() else ""
                    map["cellId"] = if (id.ci != Int.MAX_VALUE) id.ci.toString() else ""
                    map["mcc"] = id.mccString ?: ""
                    map["mnc"] = id.mncString ?: ""

                    map["rsrp"] = if (ss.rsrp != Int.MAX_VALUE) ss.rsrp else -140
                    map["rsrq"] = if (ss.rsrq != Int.MAX_VALUE) ss.rsrq else 0
                    map["rssi"] = if (ss.rssi != Int.MAX_VALUE) ss.rssi else if (ss.dbm != Int.MAX_VALUE) ss.dbm else -140
                    map["rssnr"] = if (ss.rssnr != Int.MAX_VALUE) ss.rssnr else 0
                    map["sinr"] = calculateSinr(ss.rssnr, ss.rsrq)
                    map["cqi"] = if (ss.cqi != Int.MAX_VALUE) ss.cqi else 0
                    map["asuLevel"] = ss.asuLevel
                    map["timingAdvance"] = if (ss.timingAdvance != Int.MAX_VALUE) ss.timingAdvance else 0

                    if (freq > 0) {
                        map["pathLossModels"] = calculatePathLoss(freq, info)
                    }
                }

                is CellInfoNr -> {
                    val id = info.cellIdentity as CellIdentityNr
                    val ss = info.cellSignalStrength as CellSignalStrengthNr
                    val nrarfcn = if (id.nrarfcn != Int.MAX_VALUE) id.nrarfcn else -1
                    val band = id.bands.firstOrNull() ?: 0
                    val freq = calculateNrFreq(nrarfcn)

                    map["type"] = "NR"
                    map["pci"] = if (id.pci != Int.MAX_VALUE) id.pci else -1
                    map["nrarfcn"] = nrarfcn
                    map["band"] = band
                    map["frequency"] = freq
                    map["nci"] = if (id.nci != Long.MAX_VALUE) id.nci.toString() else ""
                    map["tac"] = if (id.tac != Int.MAX_VALUE) id.tac.toString() else ""
                    map["mcc"] = id.mccString ?: ""
                    map["mnc"] = id.mncString ?: ""

                    map["rsrp"] = if (ss.ssRsrp != Int.MAX_VALUE) ss.ssRsrp else -140
                    map["rsrq"] = if (ss.ssRsrq != Int.MAX_VALUE) ss.ssRsrq else 0
                    map["sinr"] = if (ss.ssSinr != Int.MAX_VALUE) ss.ssSinr else 0
                    map["timingAdvance"] = if (ss.timingAdvanceMicros != Int.MAX_VALUE) ss.timingAdvanceMicros else 0

                    if (freq > 0) {
                        map["pathLossModels"] = calculatePathLoss(freq, info)
                    }
                }

                is CellInfoGsm -> {
                    val id = info.cellIdentity
                    val ss = info.cellSignalStrength
                    val arfcn = if (id.arfcn != Int.MAX_VALUE) id.arfcn else -1
                    val freq = calculateGsmFreq(arfcn)

                    map["type"] = "GSM"
                    map["arfcn"] = arfcn
                    map["frequency"] = freq
                    map["bsic"] = if (id.bsic != Int.MAX_VALUE) id.bsic else -1
                    map["lac"] = if (id.lac != Int.MAX_VALUE) id.lac else -1
                    map["psc"] = -1
                    map["rssi"] = if (ss.dbm != Int.MAX_VALUE) ss.dbm else 0
                    map["dbm"] = ss.dbm
                    map["mcc"] = id.mccString ?: ""
                    map["mnc"] = id.mncString ?: ""
                    map["cellId"] = if (id.cid != Int.MAX_VALUE) id.cid.toString() else ""
                    map["timingAdvance"] = if (ss.timingAdvance != Int.MAX_VALUE) ss.timingAdvance else 0

                    if (freq > 0) {
                        map["pathLossModels"] = calculatePathLoss(freq, info)
                    }
                }

                else -> return@forEach
            }

            if (map.containsKey("type")) list.add(map)
        }
        return list
    }

    private fun calculateLteFreq(earfcn: Int, band: Int): Double {
        if (earfcn == -1) return 0.0
        return when (band) {
            1 -> 2110.0 + 0.1 * (earfcn - 0)
            3 -> 1805.0 + 0.1 * (earfcn - 1200)
            7 -> 2620.0 + 0.1 * (earfcn - 2750)
            8 -> 925.0 + 0.1 * (earfcn - 3450)
            20 -> 791.0 + 0.1 * (earfcn - 6150)
            38 -> 2570.0 + 0.1 * (earfcn - 37750)
            40 -> 2300.0 + 0.1 * (earfcn - 38650)
            else -> {
                when (earfcn) {
                    in 0..599 -> 2110.0 + earfcn * 0.1
                    in 1200..1949 -> 1805.0 + (earfcn - 1200) * 0.1
                    else -> 0.0
                }
            }
        }
    }

    private fun calculateNrFreq(nrarfcn: Int): Double {
        return if (nrarfcn < 600000) nrarfcn * 0.005 else 3000.0 + (nrarfcn - 600000) * 0.015
    }

    private fun calculateGsmFreq(arfcn: Int): Double {
        return when (arfcn) {
            in 1..124 -> 935.0 + arfcn * 0.2
            in 512..885 -> 1805.2 + (arfcn - 512) * 0.2
            else -> 0.0
        }
    }

    private fun calculateSinr(rssnr: Int, rsrq: Int): Double {
        val sinr = if (rssnr != Int.MAX_VALUE && rssnr != Int.MIN_VALUE) {
            rssnr / 10.0
        } else {
            if (rsrq != Int.MAX_VALUE) (rsrq + 20).toDouble() else 0.0
        }
        return sinr.coerceIn(-30.0, 40.0)
    }

    private fun calculatePathLoss(freqMHz: Double, info: CellInfo): Map<String, Double> {
        val hb = 30.0

        // Barometric formula for altitude calculation (ISA)
        val hm = if (pressureValue > 300f) {
            val calculatedHm = 44330.0 * (1.0 - (pressureValue / 1013.25).pow(0.1903))
            calculatedHm.coerceIn(1.0, 50.0)
        } else {
            1.5
        }

        // Get RSRP for models and distance fallback
        val rsrp = when (info) {
            is CellInfoLte -> info.cellSignalStrength.rsrp
            is CellInfoNr -> (info.cellSignalStrength as CellSignalStrengthNr).ssRsrp
            is CellInfoGsm -> info.cellSignalStrength.dbm
            else -> Int.MAX_VALUE
        }

        // Filter out extremely poor signals to avoid processing garbage data
        if (rsrp == Int.MAX_VALUE || rsrp < -130) return emptyMap()

        val taKm = when (info) {
            is CellInfoLte -> {
                val ta = info.cellSignalStrength.timingAdvance
                if (ta != Int.MAX_VALUE && ta > 0) ta.toDouble() * 0.078 else -1.0
            }
            is CellInfoNr -> {
                val taMicros = (info.cellSignalStrength as CellSignalStrengthNr).timingAdvanceMicros
                // c ≈ 3e8 м/с → 0.3 км/мкс
                // d = (TA * c) / 2
                if (taMicros != Int.MAX_VALUE && taMicros > 0) (taMicros.toDouble() * 0.15).coerceIn(0.1, 10.0) else -1.0
            }
            is CellInfoGsm -> {
                val ta = info.cellSignalStrength.timingAdvance
                if (ta != Int.MAX_VALUE && ta > 0) ta.toDouble() * 0.55 else -1.0
            }
            else -> -1.0
        }

        // Distance Refinement: TA is jittery, so we use a distance fallback from RSRP
        val txPower = when {
            freqMHz < 1000 -> 46.0
            freqMHz < 2000 -> 43.0
            else -> 40.0
        }

        val d = if (taKm > 0) {
            max(0.5, taKm).coerceIn(0.5, 20.0)
        } else {
            // Distance estimation from RSRP (Inverse FSPL) as fallback
            val plFromRsrp = txPower - rsrp
            10.0.pow((plFromRsrp - 32.44 - 20 * log10(freqMHz)) / 20.0).coerceIn(0.5, 20.0)
        }

        val ahrUrban = (1.1 * log10(freqMHz) - 0.7) * hm - (1.56 * log10(freqMHz) - 0.8)

        val res = mutableMapOf<String, Double>()
        res["wavelength"] = 299.79 / freqMHz
        res["elevation_hm"] = hm

        // Free Space Path Loss (Sanity Check / Reference)
        val fspl = 32.44 + 20 * log10(freqMHz) + 20 * log10(d)
        res["loss_fspl"] = fspl

        val mainLoss = when {
            freqMHz <= 1500 -> {
                // Okumura-Hata (< 1500 MHz)
                69.55 + 26.16 * log10(freqMHz) - 13.82 * log10(hb) - ahrUrban + (44.9 - 6.55 * log10(hb)) * log10(d)
            }
            freqMHz <= 2000 -> {
                // COST-231 Hata (1500 - 2000 MHz)
                val cm = 3.0 // Urban environment constant
                46.3 + 33.9 * log10(freqMHz) - 13.82 * log10(hb) - ahrUrban + (44.9 - 6.55 * log10(hb)) * log10(d) + cm
            }
            else -> {
                // High frequency fallback (beyond standard Hata/COST-231 range)
                // Using FSPL + 20 dB as a standard urban clutter margin
                fspl + 20.0 
            }
        }

        val clutterLoss = when {
            freqMHz < 1000 -> 10
            freqMHz < 2000 -> 15
            else -> 20
        }

        val adjustedLoss = mainLoss + clutterLoss

        if (freqMHz <= 1500) res["loss_hata"] = mainLoss
        else if (freqMHz <= 2000) res["loss_cost231"] = mainLoss
        else res["loss_fallback"] = mainLoss

        res["loss_adjusted"] = adjustedLoss

        // Weighted Hybrid Model for smoother transitions
        // Near field (< 1km): Mostly FSPL
        // Transition (1-5km): Weighted average
        // Far field (> 5km): Mostly empirical models (Hata/COST-231)
        val hybrid = when {
            d < 1.0 -> fspl
            d < 5.0 -> (fspl * 0.6 + mainLoss * 0.4)
            else -> (fspl * 0.3 + mainLoss * 0.7)
        }

        // Median Filter for Noise Reduction
        val cellKey = when(info) {
            is CellInfoLte -> "LTE_${info.cellIdentity.pci}_${info.cellIdentity.earfcn}"
            is CellInfoNr -> "NR_${(info.cellIdentity as CellIdentityNr).pci}_${(info.cellIdentity as CellIdentityNr).nrarfcn}"
            is CellInfoGsm -> "GSM_${info.cellIdentity.cid}_${info.cellIdentity.arfcn}"
            else -> "UNKNOWN"
        }
        val smoothedMedian = getSmoothedLoss(cellKey, hybrid)

        // Final Kalman stage for "engineering-grade" stability
        val kalman = kalmanFilters.getOrPut(cellKey) { KalmanFilter(q = 0.05, r = if (d < 2) 0.5 else 2.0) }
        res["loss_hybrid"] = kalman.filter(smoothedMedian)

        return res
    }

    private fun getSmoothedLoss(cellKey: String, value: Double): Double {
        val history = pathLossHistory.getOrPut(cellKey) { ArrayDeque<Double>() }
        history.addLast(value)
        if (history.size > 5) history.removeFirst()
        val sortedList = history.toList().sorted()
        return sortedList[sortedList.size / 2]
    }

    private fun getNetworkUsage(): NetworkUsageData {
        val nsm = getSystemService(NETWORK_STATS_SERVICE) as NetworkStatsManager
        var totalSent = 0L
        var totalReceived = 0L

        try {
            val now = System.currentTimeMillis()
            val mobileBucket = nsm.querySummaryForDevice(NetworkCapabilities.TRANSPORT_CELLULAR, null, 0, now)
            totalSent += mobileBucket.txBytes
            totalReceived += mobileBucket.rxBytes

            try {
                val wifiBucket = nsm.querySummaryForDevice(NetworkCapabilities.TRANSPORT_WIFI, null, 0, now)
                totalSent += wifiBucket.txBytes
                totalReceived += wifiBucket.rxBytes
            } catch (_: Exception) {}

            lastNetworkData?.let {
                if (totalSent < it.totalBytesSent) totalSent = it.totalBytesSent
                if (totalReceived < it.totalBytesReceived) totalReceived = it.totalBytesReceived
            }

            var topApps: List<AppUsage>? = lastNetworkData?.topApps
            if (System.currentTimeMillis() - lastNetworkQueryTime > 15000) {
                topApps = queryTopApps(nsm)
                lastNetworkQueryTime = System.currentTimeMillis()
            }

            val result = NetworkUsageData(totalSent, totalReceived, topApps)
            lastNetworkData = result
            return result
        } catch (e: Exception) {
            Log.e(tag, "Error getting network stats: ${e.message}")
            return lastNetworkData ?: NetworkUsageData(0, 0, null)
        }
    }

    private fun queryTopApps(nsm: NetworkStatsManager): List<AppUsage> {
        val appList = mutableListOf<AppUsage>()
        val pm = packageManager
        val startTime = System.currentTimeMillis() - 24 * 60 * 60 * 1000
        val now = System.currentTimeMillis()

        try {
            val stats = nsm.querySummary(NetworkCapabilities.TRANSPORT_CELLULAR, null, startTime, now)
            val outBucket = NetworkStats.Bucket()
            val tempUsageMap = mutableMapOf<Int, Long>()
            while (stats.hasNextBucket()) {
                stats.getNextBucket(outBucket)
                tempUsageMap[outBucket.uid] = (tempUsageMap[outBucket.uid] ?: 0L) + outBucket.txBytes + outBucket.rxBytes
            }
            stats.close()

            tempUsageMap.forEach { (uid, bytes) ->
                if (bytes > 1024 * 1024) {
                    val name = pm.getNameForUid(uid) ?: "uid_$uid"
                    if (name != "android" && !name.contains("com.android.providers.media")) {
                        appList.add(AppUsage(name, bytes))
                    }
                }
            }
            return appList.sortedByDescending { it.bytes }.take(10)
        } catch (_: Exception) {}
        return emptyList()
    }

    private fun startConnectionMonitor() {
        serviceScope.launch {
            while (isActive) {
                if (System.currentTimeMillis() - lastSuccessfulSend > 20000) {
                    Log.w(tag, "Connection lost. Reconnecting...")
                    reconnect()
                }
                delay(10000)
            }
        }
    }

    private fun startCommandListener() {
        serviceScope.launch {
            while (isActive) {
                try {
                    val rawCmd = socketMutex.withLock {
                        pullSocket?.recvStr(ZMQ.DONTWAIT)
                    }
                    rawCmd?.let { jsonStr ->
                        try {
                            val cmdData = gson.fromJson(jsonStr, Map::class.java)
                            val cmd = cmdData["cmd"] as? String ?: ""

                            when (cmd) {
                                "SET_DELAY" -> {
                                    val value = (cmdData["value"] as? Double)?.toLong() ?: 500L
                                    dataCollectionDelay = value.coerceIn(100, 10000)
                                    Log.d(tag, "Command: Collection delay set to $dataCollectionDelay ms")
                                }
                                "TOGGLE_FILTER" -> {
                                    val target = cmdData["target"] as? String
                                    val state = cmdData["state"] as? Boolean ?: true
                                    when (target) {
                                        "location" -> filterLocation = state
                                        "telephony" -> filterTelephony = state
                                        "network" -> filterNetwork = state
                                    }
                                }
                                "SET_GPS_SMOOTHING" -> {
                                    smoothGps = cmdData["state"] as? Boolean ?: true
                                }
                                "RESET_HISTORY" -> {
                                    pathLossHistory.clear()
                                    kalmanFilters.clear()
                                    Log.d(tag, "Command: Histories reset")
                                }
                                "RECONNECT" -> {
                                    reconnect()
                                }
                            }
                        } catch (e: Exception) {
                            // Fallback for legacy string commands
                            when (jsonStr) {
                                "FILTER_LOCATION_ON" -> filterLocation = true
                                "FILTER_LOCATION_OFF" -> filterLocation = false
                                "FILTER_TELEPHONY_ON" -> filterTelephony = true
                                "FILTER_TELEPHONY_OFF" -> filterTelephony = false
                            }
                        }
                    }
                } catch (_: Exception) {}
                delay(1000)
            }
        }
    }

    private fun saveToFile(data: Map<String, Any?>) {
        try { logFile.appendText(gson.toJson(data) + "\n") } catch (_: Exception) {}
    }

    private fun acquireWakeLock() {
        val pm = getSystemService(POWER_SERVICE) as PowerManager
        wakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "TelephonyService::WakeLock")
        wakeLock?.acquire(10 * 60 * 1000L)
    }

    private fun createNotificationChannel() {
        val serviceChannel = NotificationChannel(channelId, "Telephony Service Channel", NotificationManager.IMPORTANCE_HIGH)
        val manager = getSystemService(NotificationManager::class.java)
        manager?.createNotificationChannel(serviceChannel)
    }

    override fun onSensorChanged(event: SensorEvent?) {
        when (event?.sensor?.type) {
            Sensor.TYPE_PRESSURE -> pressureValue = event.values[0]
            Sensor.TYPE_ROTATION_VECTOR -> {
                val rotationMatrix = FloatArray(9)
                SensorManager.getRotationMatrixFromVector(rotationMatrix, event.values)
                val orientation = FloatArray(3)
                SensorManager.getOrientation(rotationMatrix, orientation)
                // convert to degrees and normalize to [0, 360]
                var azimuth = Math.toDegrees(orientation[0].toDouble()).toFloat()
                if (azimuth < 0) azimuth += 360f
                azimuthValue = azimuth
            }
        }
    }

    override fun onAccuracyChanged(sensor: Sensor?, accuracy: Int) {}

    override fun onDestroy() {
        sensorManager.unregisterListener(this)
        serviceJob.cancel()
        if (::locationCallback.isInitialized) {
            fusedLocationClient.removeLocationUpdates(locationCallback)
        }
        runBlocking {
            socketMutex.withLock {
                closeSocketsInternal()
            }
        }
        wakeLock?.release()
        super.onDestroy()
    }

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int = START_STICKY
    override fun onBind(intent: Intent?): IBinder? = null
}
